  async getSigner() {
    if (typeof this.provider.getSigner === "function") {
      return await this.provider.getSigner();
    }
    throw new Error("Provider does not support signing");
  }

  getTokenContract(tokenAddress, signerOrProvider = this.provider) {
    return new ethers.Contract(tokenAddress, ERC20_ABI, signerOrProvider);
  }

  getRouterContract(signerOrProvider = this.provider) {
    return new ethers.Contract(this.routerAddress, ROUTER_ABI, signerOrProvider);
  }

